#!/usr/bin/env python3
"""fix.py — corrige graph/mod.rs y models/mod.rs"""
import pathlib, json, base64, subprocess, sys

FILES_B64 = {
  "src/graph/mod.rs": "",
  "src/models/mod.rs": ""
}

def main():
    print("Escribiendo archivos corregidos...")
    for path_str, b64 in FILES_B64.items():
        p = pathlib.Path(path_str)
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_bytes(base64.b64decode(b64))
        print(f"  ok  {path_str}")
    print("\ncargo test...")
    r = subprocess.run(["cargo", "test"], capture_output=True, text=True)
    print(r.stdout[-3000:])
    if r.returncode != 0:
        print("ERRORES:")
        print(r.stderr[-2000:])
        sys.exit(1)
    print("OK")

if __name__ == "__main__":
    main()
